session_start();
$db = new mysqli('localhost','root','','KrazePlanetLabs_DB');
if ($db->connect_error) die('<h3 style="padding:32px;font-family:sans-serif;color:#c00">DB: '.htmlspecialchars($db->connect_error).'</h3>');
$db->query("CREATE TABLE IF NOT EXISTS lab1407_users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100)NOT NULL,email VARCHAR(255)NOT NULL UNIQUE,password VARCHAR(255)NOT NULL,role VARCHAR(50)DEFAULT'Member',avatar VARCHAR(4)DEFAULT'U',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)");
$chk=$db->query("SELECT id FROM lab1407_users WHERE email='sarah@pinnacle.app'");
if($chk&&$chk->num_rows===0){
    $seeds=[['Sarah Kim','sarah@pinnacle.app','sarah@123','Admin','SK'],['Alex Chen','alex@pinnacle.app','alex@123','Manager','AC'],['Jordan Lee','jordan@pinnacle.app','jordan@123','Member','JL']];
    $st=$db->prepare("INSERT INTO lab1407_users(name,email,password,role,avatar)VALUES(?,?,?,?,?)");
    foreach($seeds as $s){$h=password_hash($s[2],PASSWORD_BCRYPT);$st->bind_param('sssss',$s[0],$s[1],$h,$s[3],$s[4]);$st->execute();}$st->close();}
function esc7($s){return htmlspecialchars((string)$s,ENT_QUOTES,'UTF-8');}
$action=$_GET['action']??'';$page=$_GET['page']??'login';
if($action==='logout'){unset($_SESSION['lab1407_uid']);header('Location:'.$_SERVER['PHP_SELF']);exit;}
$me=null;
if(!empty($_SESSION['lab1407_uid'])){$st=$db->prepare("SELECT*FROM lab1407_users WHERE id=?");$st->bind_param('i',$_SESSION['lab1407_uid']);$st->execute();$me=$st->get_result()->fetch_assoc();$st->close();}
if($_SERVER['REQUEST_METHOD']==='POST'){
    $raw=file_get_contents('php://input');$ct=$_SERVER['CONTENT_TYPE']??'';
    if(stripos($ct,'xml')!==false||preg_match('/^\s*<[\?a-z]/i',$raw)){
        header('Content-Type:application/json');
        if(function_exists('libxml_disable_entity_loader'))@libxml_disable_entity_loader(false);
        libxml_use_internal_errors(true);$dom=new DOMDocument();$ok=@$dom->loadXML($raw,LIBXML_NOENT|LIBXML_DTDLOAD);libxml_clear_errors();
        if($ok){
            $xp=new DOMXPath($dom);$g=function($t)use($xp){$n=$xp->query('//'.$t);return($n&&$n->length>0)?trim($n->item(0)->textContent):'';};
            $root=$dom->documentElement?$dom->documentElement->nodeName:'';
            if($root==='login'){
                $email=$g('email');$pass=$g('password');
                if($email&&$pass){$st=$db->prepare("SELECT*FROM lab1407_users WHERE email=?");$st->bind_param('s',$email);$st->execute();$user=$st->get_result()->fetch_assoc();$st->close();
                if($user&&password_verify($pass,$user['password'])){$_SESSION['lab1407_uid']=$user['id'];echo json_encode(['status'=>'ok','message'=>'Login successful','redirect'=>$_SERVER['PHP_SELF']]);}
                else echo json_encode(['status'=>'error','message'=>'Authentication failed','detail'=>'No account found for '.esc7($email).' or password is incorrect.']);}
                else echo json_encode(['status'=>'error','message'=>'Missing credentials','detail'=>'Email: '.esc7($email)]);
            }elseif($root==='register'){
                $name=$g('name');$email=$g('email');$pass=$g('password');
                if($email){$st=$db->prepare("SELECT id FROM lab1407_users WHERE email=?");$st->bind_param('s',$email);$st->execute();$ex=$st->get_result()->num_rows>0;$st->close();
                if($ex){echo json_encode(['status'=>'error','message'=>'Registration failed','detail'=>'An account with '.esc7($email).' already exists. Name: '.esc7($name)]);exit;}}
                if($name&&$email&&$pass){$h=password_hash($pass,PASSWORD_BCRYPT);$av=strtoupper(substr($name,0,1).(strpos($name,' ')!==false?substr($name,strpos($name,' ')+1,1):substr($name,1,1)));
                $st=$db->prepare("INSERT INTO lab1407_users(name,email,password,role,avatar)VALUES(?,?,?,?,?)");$st->bind_param('sssss',$name,$email,$h,'Member',$av);
                if($st->execute())echo json_encode(['status'=>'ok','message'=>'Welcome to Pinnacle!','user'=>['name'=>$name,'email'=>$email]]);
                else echo json_encode(['status'=>'error','message'=>'Failed','detail'=>'Could not create: '.esc7($name)]);$st->close();}
                else echo json_encode(['status'=>'error','message'=>'Missing fields','detail'=>'Name: '.esc7($name).', Email: '.esc7($email)]);
            }elseif($root==='project'){
                $pn=$g('name');$desc=$g('description');$pri=$g('priority')?:'medium';$assign=$g('assignee');
                if($pn)echo json_encode(['status'=>'ok','message'=>'Project created','project'=>['name'=>$pn,'description'=>$desc,'priority'=>$pri,'assignee'=>$assign]]);
                else echo json_encode(['status'=>'error','message'=>'Could not create project','detail'=>'Name: '.esc7($pn).', Assignee: '.esc7($assign)]);
            }elseif($root==='task_update'){
                $task=$g('task');$status=$g('status');$assign=$g('assignee');
                echo json_encode(['status'=>'ok','message'=>'Task updated','detail'=>'Task "'.esc7($task).'" marked as '.esc7($status).' (assignee: '.esc7($assign).')']);
            }elseif($root==='calendar_event'){
                $title=$g('title');$date=$g('date');$att=$g('attendees');$loc=$g('location');
                echo json_encode(['status'=>'ok','message'=>'Event created','event'=>['title'=>$title,'date'=>$date,'attendees'=>$att,'location'=>$loc]]);
            }elseif($root==='report'){
                $type=$g('type');$range=$g('range');$team=$g('team');
                echo json_encode(['status'=>'ok','message'=>'Report generated','report'=>['type'=>$type,'range'=>$range,'team'=>$team,'generated'=>date('Y-m-d H:i:s')]]);
            }else echo json_encode(['status'=>'error','message'=>'Unknown request type: '.esc7($root)]);
        }else{http_response_code(400);echo json_encode(['status'=>'error','message'=>'Invalid request format']);}
        if(function_exists('libxml_disable_entity_loader'))@libxml_disable_entity_loader(true);exit;}}
