<script>
var ids={proj:'projM',task:'taskM',cal:'calM',rep:'repM'};
function openM(t){document.getElementById(ids[t]).classList.add('show');}
function closeM(t){var m=document.getElementById(ids[t]);m.classList.remove('show');var r=m.querySelector('.rb');if(r)r.style.display='none';}
function xf(xml,btn,orig,resId,ok){btn.disabled=true;btn.innerHTML='<span class="sp"></span> Working...';fetch(window.location.pathname,{method:'POST',headers:{'Content-Type':'application/xml'},body:xml}).then(function(r){return r.json()}).then(function(d){btn.disabled=false;btn.innerHTML=orig;var bx=document.getElementById(resId);bx.style.display='block';if(d.status==='ok'){bx.className='rb ok';ok(d);}else{bx.className='rb er';bx.innerHTML='<i class="bi bi-x-circle me-2"></i>'+H(d.detail||d.message);}}).catch(function(){btn.disabled=false;btn.innerHTML=orig;});}
function doProj(e){e.preventDefault();var n=document.getElementById('p_name').value,d=document.getElementById('p_desc').value,p=document.getElementById('p_pri').value,a=document.getElementById('p_asgn').value;
var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<project>\n  <name>'+n+'</name>\n  <description>'+d+'</description>\n  <priority>'+p+'</priority>\n  <assignee>'+a+'</assignee>\n</project>';
xf(xml,document.getElementById('pbtn'),'<i class="bi bi-check-lg"></i> Create Project','pres',function(r){document.getElementById('pres').innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(r.message)+' — '+H(r.project.name)+' ('+H(r.project.priority)+', '+H(r.project.assignee)+')';document.getElementById('pGrid').innerHTML+='<div class="pc"><div class="pt"><span style="width:8px;height:8px;border-radius:50%;background:#6366f1;display:inline-block"></span> '+H(r.project.name)+'</div><div class="pd">'+H(r.project.description)+'</div><div class="pb"><div class="pf" style="width:0%;background:#6366f1"></div></div><div class="pm"><div class="pp" style="color:#6366f1">0%</div><div class="pa"><span style="background:#6366f1">'+H(r.project.assignee).substring(0,2).toUpperCase()+'</span></div></div></div>';noti('New project: '+r.project.name);});return false;}
function doNewTask(e){e.preventDefault();var n=document.getElementById('t_name').value,s=document.getElementById('t_status').value,a=document.getElementById('t_asgn').value;
var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<task_update>\n  <task>'+n+'</task>\n  <status>'+s+'</status>\n  <assignee>'+a+'</assignee>\n</task_update>';
xf(xml,document.getElementById('tbtn'),'<i class="bi bi-check-lg"></i> Add Task','tres',function(r){document.getElementById('tres').innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(r.detail);noti('Task: '+n);});return false;}
function doCal(e){e.preventDefault();var t=document.getElementById('c_title').value,d=document.getElementById('c_date').value,a=document.getElementById('c_att').value,l=document.getElementById('c_loc').value;
var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<calendar_event>\n  <title>'+t+'</title>\n  <date>'+d+'</date>\n  <attendees>'+a+'</attendees>\n  <location>'+l+'</location>\n</calendar_event>';
xf(xml,document.getElementById('cbtn'),'<i class="bi bi-check-lg"></i> Create Event','cres',function(r){document.getElementById('cres').innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(r.message)+' — '+H(r.event.title)+' on '+H(r.event.date)+' ('+H(r.event.attendees)+')';noti('Event: '+r.event.title);});return false;}
function doRep(e){e.preventDefault();var t=document.getElementById('r_type').value,rn=document.getElementById('r_range').value,tm=document.getElementById('r_team').value;
var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<report>\n  <type>'+t+'</type>\n  <range>'+rn+'</range>\n  <team>'+tm+'</team>\n</report>';
xf(xml,document.getElementById('rbtn'),'<i class="bi bi-download"></i> Generate','rres',function(r){document.getElementById('rres').innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(r.message)+' — '+H(r.report.type)+' ('+H(r.report.range)+') for '+H(r.report.team);noti('Report: '+r.report.type);});return false;}
function togTask(el){var ti=el.parentElement,tx=ti.querySelector('.tx'),dd=ti.querySelector('.dd'),name=tx.textContent,wasD=el.classList.contains('dn'),newS=wasD?'todo':'completed';el.classList.toggle('dn');tx.classList.toggle('cr');dd.textContent=wasD?'To Do':'Completed';
var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<task_update>\n  <task>'+name+'</task>\n  <status>'+newS+'</status>\n  <assignee><?=esc7($me['name'])?></assignee>\n</task_update>';
fetch(window.location.pathname,{method:'POST',headers:{'Content-Type':'application/xml'},body:xml}).then(function(r){return r.json()}).then(function(d){if(d.status==='ok')noti(d.detail);});}
function noti(msg){var n=document.getElementById('notif');n.innerHTML='<div class="mb"><div class="ma" style="background:#eef2ff;color:#6366f1"><i class="bi bi-bell" style="font-size:.7rem"></i></div><div><div class="mn2">'+H(msg)+'</div><div class="mr">Just now</div></div></div>'+n.innerHTML;}
function H(s){var d=document.createElement('div');d.appendChild(document.createTextNode(s));return d.innerHTML;}
</script></body></html>
